SELECT COUNT(*)
FROM sc
WHERE 1=1

    AND sc.student_no LIKE CONCAT('%', #{studentNo}, '%')


    AND sc.course_no LIKE CONCAT('%', #{courseNo}, '%')


    AND sc.buy_textbook = #{buyTextbook}


    AND sc.grade >= #{minGrade}


    AND sc.grade >=  #{maxGrade}

SELECT sc.StudentID, sc.CourseID, sc.BuyBook, sc.Grade
FROM sc
WHERE 1=1

    AND sc.student_no LIKE CONCAT('%', #{query.studentNo}, '%')


    AND sc.course_no LIKE CONCAT('%', #{query.courseNo}, '%')


    AND sc.buy_textbook = #{query.buyTextbook}


    AND sc.grade >= #{query.minGrade}


    AND sc.grade >= #{query.maxGrade}

LIMIT #{query.offset}, #{query.limit}
